      if (options.onRetry) {
        const shouldRetry = options.onRetry(attempts, e);
        if (!shouldRetry) {
          return null;
        }
      }

      // Exponential backoff with jitter
      const delay = Math.pow(2, attempts) * 1000 + Math.random() * 1000;
      await new Promise((r) => setTimeout(r, delay));
    }
  }
  return null;
}

