    totalSessionTimeMs -
      (totalWaitServerSuccessTimeMs +
        totalWaitServerErrorTimeMs +
        totalWaitServerCancelTimeMs +
        totalWaitToolsTimeMs +
        totalWaitUserTimeMs)
