export async function runWithRetry<T>(
  operation: () => Promise<T>,
  options: RetryOptions = {}
): Promise<T | null> {
  const maxRetries = options.maxRetries ?? 3;
  let attempts = 0;

  while (attempts <= maxRetries) {
